const fs = require('fs');
const file = 'src/pages/InventoryPage.jsx';
let content = fs.readFileSync(file, 'utf8');

const target1 = `              <div className="input-group">
                <label className="input-label">Type</label>
                <select className="select" value={catForm.type} onChange={e => setCatForm(f => ({ ...f, type: e.target.value }))}>
                  {config.isKitchenEnabled !== false && <option value="kitchen">{config.kitchenLabel || 'Kitchen'}</option>}
                  {config.isBarEnabled !== false && <option value="bar">{config.barLabel || 'Bar'}</option>}
                </select>
              </div>`;

const rep1 = `              <div className="input-group">
                <label className="input-label">Type (Department)</label>
                <select className="select" value={catForm.type} onChange={e => setCatForm(f => ({ ...f, type: e.target.value }))}>
                  {(config.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}]).map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
                </select>
              </div>`;

const target2 = `  const barCategories = categories.filter(c => c.type !== 'kitchen');
  const kitchenCategories = categories.filter(c => c.type === 'kitchen');`;
const rep2 = `  // Fallback map in case category type doesn't exist
  const getDeptName = (deptId) => {
    const d = (config.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}]).find(x => x.id === deptId);
    return d ? d.name : 'Other';
  };`;

content = content.replace(target1, rep1).replace(target2, rep2);

// Re-write the category list grouping replacing the old hardcoded blocks
// This is tricky, let's just make it render categories straight up or grouped dynamically

fs.writeFileSync(file, content, 'utf8');

const fs = require('fs');
const file = 'src/pages/SettingsPage.jsx';
let content = fs.readFileSync(file, 'utf8');

// We need to replace the DEPARTMENTS section
const newSection = `
      <div className="config-section">
        <h3 className="config-section-title">?? DEPARTMENTS</h3>
        <p style={{ color: 'var(--text-secondary)', fontSize: '11px', marginBottom: '12px' }}>
          Add or remove service areas like Kitchen, Bar, Shisha Lounge, etc.
        </p>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginBottom: '12px' }}>
          {(form.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}]).map((dept, idx) => (
             <div key={dept.id} style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
               <input className="input" value={dept.name} onChange={e => {
                  const newDepts = [...(form.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}])];
                  newDepts[idx].name = e.target.value;
                  setForm(f => ({ ...f, departments: newDepts }));
               }} />
               <button className="btn btn-ghost" style={{ color: 'var(--brand-danger)' }} onClick={() => {
                  const newDepts = [...(form.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}])];
                  newDepts.splice(idx, 1);
                  setForm(f => ({ ...f, departments: newDepts }));
               }}>X</button>
             </div>
          ))}
        </div>
        <button className="btn btn-secondary btn-sm" onClick={() => {
           const newDepts = [...(form.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}])];
           newDepts.push({ id: 'dept_' + Date.now(), name: 'New Dept' });
           setForm(f => ({ ...f, departments: newDepts }));
        }}>+ ADD DEPARTMENT</button>
      </div>`;

const startIdx = content.indexOf('<h3 className="config-section-title">?? DEPARTMENTS</h3>');
const outerDivStart = content.lastIndexOf('<div className="config-section">', startIdx);
const endIdx = content.indexOf('<div className="config-section"', outerDivStart + 10);
const replaceRangeEnd = content.indexOf('<div className="config-section"', outerDivStart + 10) || (content.lastIndexOf('</div>') - 10); // Find next section

// Let's use regex for safety
const updated = content.replace(/<div className="config-section">\s*<h3 className="config-section-title">?? DEPARTMENTS<\/h3>[\s\S]*?<\/div>\s*<div className="config-section"/, newSection + '\n\n      <div className="config-section"');

if (updated !== content) {
    fs.writeFileSync(file, updated, 'utf8');
    console.log('Updated SettingsPage.jsx');
} else {
    console.log('Failed to match regex');
}

import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { syncAll, setTenant, getTenant, subscribeToChanges } from '../store/data';

const ToastContext = createContext();

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);
  const addToast = useCallback((message, type = 'info', duration = 3000) => {
    const id = Date.now();
    setToasts([{ id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, duration);
  }, []);
  return (
    <ToastContext.Provider value={{ addToast }}>
      {children}
      <div className="toast-container">
        {toasts.map(t => (
          <div key={t.id} className={`toast toast-${t.type}`}>{t.message}</div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export const useToast = () => useContext(ToastContext);

// ===== APP CONTEXT =====
const AppContext = createContext();

export function AppProvider({ children }) {
  const theme = 'light';
  const [tenantId, setTenantId] = useState(() => localStorage.getItem('rg_tenant_id'));
  const [currentUser, setCurrentUser] = useState(() => {
    try {
      const u = localStorage.getItem('rg_current_user');
      return u ? JSON.parse(u) : null;
    } catch { return null; }
  });

  const [data, setData] = useState({
    tables: [], sections: [], categories: [], menu_items: [], users: [], orders: [], order_items: [], bills: [], bill_items: [], sessions: [],
    config: { restaurantName: 'RestoGrow', currency: '₹', taxRate: 0, serviceChargeRate: 0 },
    restaurant: { status: 'active', name: '' }
  });

  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  // Check URL for RID (Restaurant ID)
  useEffect(() => {
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const rid = params.get('rid');
    if (rid) {
      localStorage.setItem('rg_tenant_id', rid);
      setTenantId(rid);
      setTenant(rid);
    } else if (tenantId) {
      setTenant(tenantId);
    }
  }, [tenantId]);

  const loadData = useCallback(async () => {
    if (!getTenant()) {
      setLoading(false);
      return;
    }
    setRefreshing(true);
    try {
      const result = await syncAll();
      if (result) {
        setData(prev => {
          // Merge logic: only overwrite if result has data for that table
          const newData = { ...prev };
          Object.keys(result).forEach(k => {
            if (result[k] !== undefined) newData[k] = result[k];
          });
          return newData;
        });
      }
    } catch (err) {
      console.error('Sync error:', err);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    let sub = null;
    if (getTenant()) {
      sub = subscribeToChanges(() => loadData());
    }
    return () => { if (sub) sub.unsubscribe(); };
  }, [loadData, tenantId]);

  const login = useCallback(async (user) => {
    setCurrentUser(user);
    localStorage.setItem('rg_current_user', JSON.stringify(user));
    if (user.restaurant_id) {
      setTenantId(user.restaurant_id);
      localStorage.setItem('rg_tenant_id', user.restaurant_id);
      setTenant(user.restaurant_id);
    }
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
    localStorage.removeItem('rg_current_user');
    setTenantId(null);
    localStorage.removeItem('rg_tenant_id');
    setTenant(null);
    window.location.hash = '/'; // Redirect to login
  }, []);

  const refresh = useCallback(async () => { await loadData(); }, [loadData]);

  const currentSession = (data.sessions || []).find(s => s.status === 'active') || null;

  return (
    <AppContext.Provider value={{
      theme, currentUser, login, logout, tenantId,
      config: data.config,
      tables: data.tables,
      sections: data.sections,
      menuItems: data.menu_items || [],
      categories: data.categories,
      orders: data.orders,
      bills: data.bills,
      users: data.users,
      sessions: data.sessions,
      inventory_log: data.inventory_log || [],
      restaurant: data.restaurant,
      currentSession,
      refresh,
      loading,
      refreshing
    }}>
      {children}
    </AppContext.Provider>
  );
}

export const useApp = () => useContext(AppContext);

import { useState, useMemo, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp, useToast } from '../context/AppContext';
import {
  getOrderForTable, addItemToOrder, updateOrderItem, removeOrderItem,
  createOrder, generateBill, cancelOrder
} from '../store/data';
import { printSplitKOT, printBillDirect } from '../utils/print';
import { Search, ArrowLeft, Plus, Minus, Trash2, StickyNote, Printer, Wine, Coffee, CreditCard, Banknote, Smartphone, Receipt } from 'lucide-react';

export default function OrderPage() {
  const { tableId } = useParams();
  const navigate = useNavigate();
  const { tables = [], menuItems = [], categories = [], config = {}, refresh, currentUser } = useApp();
  const { addToast } = useToast();
  const isAdmin = currentUser?.role === 'admin';

  const table = useMemo(() => (tables || []).find(t => t.id === tableId), [tables, tableId]);
  const [order, setOrder] = useState(null);
  const depts = useMemo(() => config.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}], [config]);
  const [activeDeptId, setActiveDeptId] = useState(depts[0]?.id || 'kitchen');
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [noteModal, setNoteModal] = useState(null);
  const [noteText, setNoteText] = useState('');
  const [showKOTMenu, setShowKOTMenu] = useState(false);
  const [directBillModal, setDirectBillModal] = useState(false);
  const [paymentMode, setPaymentMode] = useState('Cash');
  const [discount, setDiscount] = useState(0);
  const [busy, setBusy] = useState(false);
  const [orderLoading, setOrderLoading] = useState(true);

  // Load order on mount
  const loadOrder = useCallback(async () => {
    if (!tableId) return;
    try {
      let existingOrder = await getOrderForTable(tableId);
      if (!existingOrder && table?.status === 'available') {
        await createOrder(tableId, table.label || `T${table.number}`);
        existingOrder = await getOrderForTable(tableId);
        refresh();
      }
      setOrder(existingOrder);
    } catch (e) {
      console.error('Load order error:', e);
      addToast('Order loading failed: ' + (e.message || 'Unknown'), 'error');
      setOrder(null);
    } finally {
      setOrderLoading(false);
    }
  }, [tableId, table, refresh, addToast]);

  useEffect(() => { loadOrder(); }, [loadOrder]);

  const safeItems = order?.items || [];

  const activeDept = useMemo(() => depts.find(d => d.id === activeDeptId) || depts[0], [depts, activeDeptId]);

  // Classify categories
  const deptCategories = useMemo(() => (categories || []).filter(c => c.type === activeDept?.id), [categories, activeDept]);
  const deptCatIds = useMemo(() => deptCategories.map(c => c.id), [deptCategories]);

  // Filter items
  const isSearching = searchQuery.length > 0;
  const q = searchQuery.toLowerCase();

  const deptItems = useMemo(() => {
    let items = (menuItems || []).filter(i => deptCatIds.includes(i.categoryId));
    if (categoryFilter !== 'all') items = items.filter(i => i.categoryId === categoryFilter);
    if (isSearching) {
      items = (menuItems || []).filter(i => i.name?.toLowerCase().includes(q) || i.code?.toLowerCase()?.includes(q));
    }
    return items;
  }, [menuItems, categoryFilter, deptCatIds, isSearching, q]);

  const handleAddItem = async (menuItem) => {
    if (!order) { addToast("Order not initialized yet", "warning"); return; }
    if (busy) return;
    setBusy(true);
    try {
      const cat = (categories || []).find(c => c.id === menuItem.categoryId);
      await addItemToOrder(order.id, { ...menuItem, categoryType: cat?.type || 'bar' });
      await loadOrder();
      addToast(`+ ${menuItem.name}`, 'success');
    } catch (e) { addToast(e.message || 'Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleQtyChange = async (itemId, delta) => {
    if (!order || busy) return;
    const item = safeItems.find(i => i.id === itemId);
    if (!item) return;
    const newQty = item.quantity + delta;
    setBusy(true);
    try {
      if (newQty <= 0) await removeOrderItem(order.id, itemId);
      else await updateOrderItem(order.id, itemId, { quantity: newQty });
      await loadOrder();
    } catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleRemoveItem = async (itemId) => {
    if (!order || busy) return;
    setBusy(true);
    try { await removeOrderItem(order.id, itemId); await loadOrder(); }
    catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleAddNote = async () => {
    if (!order || !noteModal || busy) return;
    setBusy(true);
    try { await updateOrderItem(order.id, noteModal.id, { note: noteText }); await loadOrder(); }
    catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
    setNoteModal(null);
    setNoteText('');
  };

  const handleGoToBilling = async () => {
    if (!order || safeItems.length === 0) { addToast('Add items first', 'warning'); return; }
    if (busy) return;
    setBusy(true);
    try {
      await refresh();
      navigate(`/billing/${order.id}`);
    } finally {
      setBusy(false);
    }
  };

  // KOT print
  const handlePrintSplitKOT = () => {
    if (!order || safeItems.length === 0) { addToast('No items', 'warning'); return; }
    try {
      const tableLabel = table?.label || table?.number;
      printSplitKOT(order, tableLabel, categories, config);
      addToast('KOT printed for respective departments', 'success');
    } catch (e) { addToast('Print failed', 'error'); }
    setShowKOTMenu(false);
  };

  const handlePrintDeptOnly = (deptId) => {
    if (!order) return;
    try {
      const tableLabel = table?.label || table?.number;
      // Filter the order items to only include those belonging to deptId categories
      const deptCatIdsLocal = categories.filter(c => c.type === deptId).map(c => c.id);
      const filteredOrder = {
        ...order,
        items: order.items.filter(i => deptCatIdsLocal.includes(i.categoryId))
      };

      if (filteredOrder.items.length === 0) {
        addToast('No items for this department', 'warning');
        return;
      }

      const res = printSplitKOT(filteredOrder, tableLabel, categories, config);
      addToast('Department KOT printed', 'success');
    } catch (e) { addToast('Print failed', 'error'); }
    setShowKOTMenu(false);
  };

  // Direct bill
  const handleCancelOrder = async () => {
    if (!order || busy) return;
    if (!window.confirm('Cancel this order and free the table?')) return;
    setBusy(true);
    try {
      await cancelOrder(order.id, table.id);
      await refresh();
      addToast('Order cancelled', 'info');
      navigate('/tables');
    } catch (e) {
      addToast('Failed: ' + (e.message || ''), 'error');
    } finally {
      setBusy(false);
    }
  };

  const handleDirectBill = async () => {
    if (!order || safeItems.length === 0 || busy) return;
    setBusy(true);
    try {
      const result = await generateBill(order.id, paymentMode, discount);
      if (result?.bill) {
        try { printBillDirect({ ...result.bill, currency: config.currency }); } catch {}
        await refresh();
        addToast('Direct bill generated & printed', 'success');
        setDirectBillModal(false);
        navigate('/tables');
      } else {
        addToast('Failed to generate bill', 'error');
      }
    } catch (e) { addToast('Failed: ' + (e.message || ''), 'error'); }
    finally { setBusy(false); }
  };

  const subtotal = safeItems.reduce((s, i) => s + ((i.price || 0) * (i.quantity || 0)), 0);
  const tax = (subtotal * (config.taxRate || 0)) / 100;
  const serviceCharge = (subtotal * (config.serviceChargeRate || 0)) / 100;
  const total = subtotal + tax + serviceCharge;
  // Generic counts removed. total is sufficient.

  if (!table && !orderLoading) {
    return (
      <div className="page-content">
        <div className="empty-state">
          <p className="empty-state-title">Table not found</p>
          <button className="btn btn-primary" onClick={() => navigate('/tables')}>Back</button>
        </div>
      </div>
    );
  }

  if (orderLoading) {
    return (
      <div className="page-content">
        <div className="resto-loader">
          <div className="resto-logo-spin">RG</div>
          <div className="resto-loader-text">Loading order...</div>
        </div>
      </div>
    );
  }

  const renderItemCard = (item) => {
    // Only gray out if they are actively using stock tracking (e.g. stock <= 0 and they manually manage it)
    // To prevent false blockages, we won't block clicking here anymore.
    const isOOS = false; // Bypass visual OOS for now so users can select unconditionally
    return (
      <div
        key={item.id}
        className="menu-item-card"
        onClick={() => !isOOS && handleAddItem(item)}
        style={{
          opacity: isOOS ? 0.25 : busy ? 0.6 : 1,
          pointerEvents: isOOS || busy ? 'none' : 'auto',
          filter: isOOS ? 'grayscale(1)' : undefined,
        }}
      >
        <div className="menu-item-name">{item.name}</div>
        {item.code && <div className="menu-item-code">{item.code}</div>}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 'auto', paddingTop: '4px' }}>
          <div className="menu-item-price">{config.currency}{item.price}</div>
          {item.stock !== undefined && item.stock !== null && item.stock <= 5 && item.stock > 0 && (
            <span style={{ fontSize: '9px', color: 'var(--brand-danger)', fontFamily: 'var(--font-mono)' }}>LOW:{item.stock}</span>
          )}
          {isOOS && <span className="badge badge-danger">OUT</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="order-layout">
      {/* Left: Menu */}
      <div className="menu-panel">
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <button className="btn btn-ghost btn-icon" onClick={() => navigate('/tables')} title="Back">
            <ArrowLeft size={16} />
          </button>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 800, fontFamily: 'var(--font-mono)', fontSize: '13px' }}>
              {table?.label || `T${table?.number}`} {table?.customerName && `— ${table.customerName}`}
            </div>
          </div>
          <div style={{ position: 'relative' }}>
            <button className="btn btn-sm btn-secondary" onClick={() => setShowKOTMenu(!showKOTMenu)} title="Print KOT">
              <Printer size={12} /> KOT ▾
            </button>
            {showKOTMenu && (
              <div className="kot-dropdown" style={{ minWidth: '200px' }}>
                <button className="kot-dropdown-item" onClick={handlePrintSplitKOT}>
                  <Printer size={12} /> <span>Print All KOT</span>
                  <span className="kot-dropdown-sub">Split auto‑detect</span>
                </button>
                {depts.map(dept => {
                   const deptCount = safeItems.filter(i => categories.find(c => c.id === i.categoryId)?.type === dept.id).length;
                   return (
                     <button key={dept.id} className="kot-dropdown-item bar" onClick={() => handlePrintDeptOnly(dept.id)}>
                       <Printer size={12} /> <span>{dept.name} KOT Only</span>
                       <span className="kot-dropdown-sub">{deptCount} items</span>
                     </button>
                   );
                })}
              </div>
            )}
          </div>
        </div>

        <div className="search-input-wrapper">
          <Search />
          <input className="input" placeholder="Search all items..." value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                if (deptItems.length === 1) { handleAddItem(deptItems[0]); setSearchQuery(''); }
              }
              if (e.key === 'Escape') { setSearchQuery(''); e.target.blur(); }
            }}
          />
        </div>

        <div className="category-tabs compact" style={{ padding: '0 8px 8px', borderBottom: '1px solid var(--border-color)', marginBottom: '8px' }}>
          {depts.map(dept => (
             <button key={dept.id} className={`category-tab ${activeDeptId === dept.id ? 'active' : ''}`} onClick={() => { setActiveDeptId(dept.id); setCategoryFilter('all'); }}>
                {dept.name}
             </button>
          ))}
        </div>

        <div className="menu-split-container" style={{ display: 'block', height: 'calc(100% - 150px)', overflowY: 'auto' }}>
            <div className="menu-split-section" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
              {!isSearching && (
                <div className="category-tabs compact" style={{ padding: '0 10px', marginBottom: '8px' }}>
                  <button className={`category-tab ${categoryFilter === 'all' ? 'active' : ''}`} onClick={() => setCategoryFilter('all')}>ALL</button>
                  {deptCategories.map(cat => (
                    <button key={cat.id} className={`category-tab ${categoryFilter === cat.id ? 'active' : ''}`} onClick={() => setCategoryFilter(cat.id)}>
                      {cat.icon} {cat.name}
                    </button>
                  ))}
                </div>
              )}
              <div className="menu-items-grid compact" style={{ padding: '0 10px 10px' }}>
                {deptItems.map(renderItemCard)}
                {deptItems.length === 0 && <div className="empty-state" style={{ gridColumn: '1/-1', padding: '12px' }}><p className="empty-state-text" style={{ fontSize: '10px' }}>No items</p></div>}
              </div>
            </div>
        </div>
      </div>

      {/* Right: Order Panel */}
      <div className="order-panel">
        <div className="order-panel-header">
          <span style={{ fontWeight: 700, fontFamily: 'var(--font-mono)', fontSize: '12px' }}>ORDER</span>
          <span className="badge badge-info">{safeItems.length} items</span>
        </div>

        <div className="order-items-list">
          {safeItems.length > 0 ? (
            safeItems.map(item => (
              <div key={item.id} className="order-item">
                <div className="order-item-info">
                  <div className="order-item-name">
                    {item.name}
                    <span style={{
                      fontSize: '8px', marginLeft: '4px', padding: '1px 3px',
                      borderRadius: '2px', fontWeight: 700,
                      background: item.categoryType === 'kitchen' ? 'rgba(253, 203, 110, 0.2)' : 'rgba(108, 92, 231, 0.2)',
                      color: item.categoryType === 'kitchen' ? 'var(--brand-warning)' : 'var(--brand-primary-light)',
                    }}>
                      {item.categoryType === 'kitchen' ? 'K' : 'B'}
                    </span>
                  </div>
                  {item.note && <div className="order-item-note">→ {item.note}</div>}
                </div>
                <div className="qty-controls">
                  <button className="qty-btn" onClick={() => handleQtyChange(item.id, -1)} disabled={busy}><Minus size={10} /></button>
                  <span className="qty-value">{item.quantity}</span>
                  <button className="qty-btn" onClick={() => handleQtyChange(item.id, 1)} disabled={busy}><Plus size={10} /></button>
                </div>
                <div className="order-item-price">{config.currency}{(item.price || 0) * (item.quantity || 0)}</div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1px' }}>
                  <button className="btn btn-ghost btn-sm" onClick={() => { setNoteModal(item); setNoteText(item.note || ''); }}>
                    <StickyNote size={10} />
                  </button>
                  <button className="btn btn-ghost btn-sm" style={{ color: 'var(--brand-danger)' }} onClick={() => handleRemoveItem(item.id)} disabled={busy}>
                    <Trash2 size={10} />
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div className="empty-state">
              <p className="empty-state-title" style={{ fontSize: '11px' }}>Empty</p>
              <p className="empty-state-text">Click items to add</p>
            </div>
          )}
        </div>

        {/* Order Actions */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '8px', padding: '12px' }}>
          {safeItems.length > 0 && (
            <div className="order-actions" style={{ gridTemplateColumns: isAdmin ? '1fr 1fr 1fr' : '1fr 1fr', gap: '8px', marginBottom: '8px' }}>
              <button className="btn btn-secondary btn-lg" onClick={handlePrintSplitKOT}><Printer size={14} /> KOT</button>
              {isAdmin && (
                <button className="btn btn-warning btn-lg" onClick={() => setDirectBillModal(true)} title="Direct bill without KOT">
                  <Receipt size={14} /> DIRECT
                </button>
              )}
              <button className="btn btn-success btn-lg" onClick={handleGoToBilling}>BILL</button>
            </div>
          )}
          <button className="btn btn-ghost" style={{ color: 'var(--brand-danger)', width: '100%' }} onClick={handleCancelOrder} disabled={busy}>
             CANCEL ORDER
          </button>
        </div>
      </div>

      {/* Note Modal */}
      {noteModal && (
        <div className="modal-backdrop" onClick={() => setNoteModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">NOTE — {noteModal.name}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setNoteModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <textarea className="input" placeholder="e.g., No ice, extra lime..." value={noteText}
                onChange={e => setNoteText(e.target.value)} rows={2} autoFocus
                onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleAddNote(); } }}
              />
              <div style={{ display: 'flex', gap: '4px', marginTop: '8px', flexWrap: 'wrap' }}>
                {['No ice', 'Extra lime', 'On the rocks', 'Neat', 'With soda', 'Double'].map(q => (
                  <button key={q} className="btn btn-sm btn-secondary" onClick={() => setNoteText(prev => prev ? `${prev}, ${q}` : q)}>{q}</button>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setNoteModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleAddNote} disabled={busy}>Save</button>
            </div>
          </div>
        </div>
      )}

      {/* Direct Bill Modal */}
      {directBillModal && (
        <div className="modal-backdrop" onClick={() => setDirectBillModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">DIRECT BILL — No KOT</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setDirectBillModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <p style={{ fontSize: '11px', color: 'var(--text-secondary)', marginBottom: '12px' }}>
                Generate bill directly without printing KOT. Ideal for counter items and takeaway.
              </p>
              <div style={{ marginBottom: '12px', maxHeight: '150px', overflow: 'auto', background: 'var(--bg-tertiary)', borderRadius: 'var(--radius-md)', padding: '8px' }}>
                {safeItems.map(item => (
                  <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '2px 0', fontSize: '11px' }}>
                    <span>{item.name} ×{item.quantity}</span>
                    <span style={{ fontFamily: 'var(--font-mono)', fontWeight: 600 }}>{config.currency}{(item.price || 0) * (item.quantity || 0)}</span>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: '11px', fontWeight: 700, fontFamily: 'var(--font-mono)', marginBottom: '8px', color: 'var(--text-secondary)' }}>PAYMENT</div>
              <div className="payment-modes" style={{ marginBottom: '12px' }}>
                {[{ mode: 'Cash', icon: Banknote }, { mode: 'Card', icon: CreditCard }, { mode: 'UPI', icon: Smartphone }].map(p => (
                  <button key={p.mode} className={`payment-mode-btn ${paymentMode === p.mode ? 'active' : ''}`}
                    onClick={() => setPaymentMode(p.mode)}><p.icon size={18} /><span>{p.mode}</span></button>
                ))}
              </div>
              <div className="input-group">
                <label className="input-label">Discount (%)</label>
                <input type="number" className="input" value={discount}
                  onChange={e => setDiscount(Math.max(0, Math.min(100, Number(e.target.value) || 0)))} min="0" max="100" />
              </div>
              <div className="order-summary-row total" style={{ marginTop: '8px' }}>
                <span>TOTAL</span>
                <span>{config.currency}{Math.round(total - (subtotal * discount / 100))}</span>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setDirectBillModal(false)}>Cancel</button>
              <button className="btn btn-success btn-lg" onClick={handleDirectBill} disabled={busy}>
                <Receipt size={14} /> {busy ? 'GENERATING...' : 'GENERATE & PRINT'}
              </button>
            </div>
          </div>
        </div>
      )}

      {showKOTMenu && <div style={{ position: 'fixed', inset: 0, zIndex: 99 }} onClick={() => setShowKOTMenu(false)} />}
    </div>
  );
}

import { useState, useMemo, useEffect, useCallback } from 'react';
import { useApp, useToast } from '../context/AppContext';
import {
  getOrderForTable, addItemToOrder, updateOrderItem, removeOrderItem,
  createOrder, generateBill, cancelOrder
} from '../store/data';
import { printSplitKOT, printBillDirect } from '../utils/print';
import {
  Search, Plus, Minus, Trash2, ArrowLeft, Printer, Wine, Coffee,
  X, StickyNote, LogOut, Receipt, CreditCard, Banknote, Smartphone, RefreshCw, Package
} from 'lucide-react';

export default function StaffMobileDashboard() {
  const { tables = [], sections = [], menuItems = [], categories = [], config = {}, refresh, currentSession, logout, refreshing = false } = useApp();
  const { addToast } = useToast();

  const [selectedTableId, setSelectedTableId] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const depts = useMemo(() => config.departments || [{id:'kitchen', name:'Kitchen'}, {id:'bar', name:'Bar'}], [config]);
  const [activeDeptId, setActiveDeptId] = useState(depts[0]?.id || 'kitchen');
  const [activeCategory, setActiveCategory] = useState('all');
  const [noteModal, setNoteModal] = useState(null);
  const [noteText, setNoteText] = useState('');
  const [customerModal, setCustomerModal] = useState(null);
  const [customerName, setCustomerName] = useState('');
  const [billModal, setBillModal] = useState(false);
  const [paymentMode, setPaymentMode] = useState('Cash');
  const [discount, setDiscount] = useState(0);
  const [order, setOrder] = useState(null);
  const [busy, setBusy] = useState(false);

  const selectedTable = useMemo(() =>
    tables.find(t => t.id === selectedTableId) || null,
  [tables, selectedTableId]);

  // Load order when table selected
  const loadOrder = useCallback(async () => {
    if (!selectedTableId) { setOrder(null); return; }
    try {
      const o = await getOrderForTable(selectedTableId);
      setOrder(o);
    } catch { setOrder(null); }
  }, [selectedTableId]);

  useEffect(() => { loadOrder(); }, [loadOrder]);

  // Reload order when tables data refreshes (realtime)
  useEffect(() => {
    if (selectedTableId) loadOrder();
  }, [tables]); // eslint-disable-line

  const safeItems = order?.items || [];

  const deptCategories = useMemo(() => (categories || []).filter(c => c.type === activeDeptId), [categories, activeDeptId]);

  const filteredItems = useMemo(() => {
    const q = searchQuery.toLowerCase();
    const tabCatIds = deptCategories.map(c => c.id);
    let items = (menuItems || []).filter(i => tabCatIds.includes(i.categoryId));
    if (activeCategory !== 'all') items = items.filter(i => i.categoryId === activeCategory);
    if (q) items = items.filter(i => i.name?.toLowerCase().includes(q) || i.code?.toLowerCase()?.includes(q));
    return items;
  }, [menuItems, activeCategory, searchQuery, deptCategories]);

  const handleTableClick = (table) => {
    if (!currentSession) { addToast('Start a session first!', 'warning'); return; }
    if (table.status === 'available') {
      setCustomerModal(table);
    } else {
      setSelectedTableId(table.id);
    }
  };

  const handleBack = () => {
    setSelectedTableId(null);
    setOrder(null);
    setSearchQuery('');
    setActiveCategory('all');
  };

  const handleStartOrder = async () => {
    if (!customerModal || busy) return;
    setBusy(true);
    const table = customerModal;
    try {
      await createOrder(table.id, table.label || `T${table.number}`, customerName);
      await refresh();
      addToast(`${table.label} — Order started`, 'success');
      setCustomerModal(null);
      setCustomerName('');
      setSelectedTableId(table.id);
    } catch (e) { addToast('Failed: ' + (e.message || 'Unknown error'), 'error'); }
    finally { setBusy(false); }
  };

  const handleAddItem = async (menuItem) => {
    if (!order) { addToast("Order not initialized yet", "warning"); return; }
    if (busy) return;
    // Removed strict stock check to allow adding items when inventory isn't explicitly tracked

    setBusy(true);
    try {
      const cat = (categories || []).find(c => c.id === menuItem.categoryId);
      await addItemToOrder(order.id, { ...menuItem, categoryType: cat?.type || 'bar' });
      // Just reload order, don't do full app sync for speed
      await loadOrder();
      addToast(`+ ${menuItem.name}`, 'success');
    } catch (e) {
      addToast(e.message || 'Failed to add item', 'error');
    } finally { setBusy(false); }
  };

  const handleQtyChange = async (itemId, delta) => {
    if (!order || busy) return;
    const item = safeItems.find(i => i.id === itemId);
    if (!item) return;
    const newQty = item.quantity + delta;
    setBusy(true);
    try {
      if (newQty <= 0) await removeOrderItem(order.id, itemId);
      else await updateOrderItem(order.id, itemId, { quantity: newQty });
      await loadOrder();
    } catch (e) { addToast(e.message || 'Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleRemoveItem = async (itemId) => {
    if (!order || busy) return;
    setBusy(true);
    try {
      await removeOrderItem(order.id, itemId);
      await loadOrder();
    } catch (e) { addToast(e.message || 'Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleAddNote = async () => {
    if (!order || !noteModal || busy) return;
    setBusy(true);
    try {
      await updateOrderItem(order.id, noteModal.id, { note: noteText });
      await loadOrder();
      setNoteModal(null);
      setNoteText('');
    } catch (e) { addToast(e.message || 'Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleCancelOrder = async () => {
    if (!order || busy) return;
    if (!window.confirm('Cancel this order and free the table?')) return;
    setBusy(true);
    try {
      await cancelOrder(order.id, selectedTableId);
      await refresh();
      addToast('Order cancelled', 'info');
      handleBack();
    } catch (e) {
      addToast('Failed: ' + (e.message || ''), 'error');
    } finally {
      setBusy(false);
    }
  };

  const handlePrintSplitKOT = () => {
    if (!order || safeItems.length === 0) { addToast('No items to print', 'warning'); return; }
    try {
      const tableLabel = selectedTable?.label || selectedTable?.number;
      printSplitKOT(order, tableLabel, categories, config);
      addToast('KOT printed', 'success');
    } catch (e) { addToast('Print failed: ' + (e.message || ''), 'error'); }
  };

  const handleGenerateBill = async () => {
    if (!order || safeItems.length === 0 || busy) return;
    setBusy(true);
    try {
      const result = await generateBill(order.id, paymentMode, discount);
      if (result?.bill) {
        try { printBillDirect({ ...result.bill, currency: config.currency }); } catch {}
        await refresh();
        addToast('Bill generated & printed', 'success');
        setBillModal(false);
        setSelectedTableId(null);
        setOrder(null);
      } else {
        addToast('Failed to generate bill', 'error');
      }
    } catch (e) { addToast('Failed: ' + (e.message || ''), 'error'); }
    finally { setBusy(false); }
  };

  const subtotal = safeItems.reduce((s, i) => s + ((i.price || 0) * (i.quantity || 0)), 0);
  const tax = (subtotal * (config.taxRate || 0)) / 100;
  const serviceCharge = (subtotal * (config.serviceChargeRate || 0)) / 100;
  const discountAmt = (subtotal * discount) / 100;
  const total = subtotal + tax + serviceCharge - discountAmt;



  // ===== TABLE VIEW =====
  if (!selectedTableId) {
    return (
      <div className="staff-mobile">
        <div className="staff-mobile-header" style={{ position: 'sticky', top: 0, zIndex: 100 }}>
          <div className="staff-mobile-brand">
            <div className="staff-brand-icon">RG</div>
            <div>
              <div className="staff-brand-name">{config.restaurantName || 'RestoGrow'}</div>
              <div className="staff-brand-sub">
                {currentSession
                  ? <span className="staff-session-live"><span className="pulse-dot-sm" /> LIVE</span>
                  : <span style={{ color: 'var(--brand-danger)' }}>NO SESSION</span>
                }
              </div>
            </div>
          </div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button className="staff-sync-btn" onClick={refresh} disabled={refreshing} title="Refresh">
              <RefreshCw size={16} className={refreshing ? 'spin' : ''} />
            </button>
            <button className="staff-logout-btn" onClick={logout}><LogOut size={16} /></button>
          </div>
        </div>

        {refreshing && tables.length === 0 ? (
          <div className="resto-loader">
            <div className="resto-logo-spin">RG</div>
            <div className="resto-loader-text">Syncing...</div>
          </div>
        ) : (
          <div className="staff-tables-scroll">
            {(sections || []).length === 0 && (
              <div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-tertiary)' }}>
                <p>No sections found</p>
                <button className="btn btn-secondary" onClick={refresh} style={{ marginTop: '8px' }}>Try Re-syncing</button>
              </div>
            )}
            {(sections || []).map(section => {
              const sectionTables = (tables || []).filter(t => t.sectionId === section.id);
              if (sectionTables.length === 0) return null;
              return (
                <div key={section.id} className="staff-section">
                  <div className="staff-section-header" style={{ '--sec-color': section.color }}>
                    <span>{section.icon} {section.name}</span>
                    <span className="staff-section-count">{sectionTables.filter(t => t.status === 'occupied').length}/{sectionTables.length}</span>
                  </div>
                  <div className="staff-table-grid">
                    {sectionTables.map(table => (
                      <div key={table.id} className={`staff-table-card ${table.status || 'available'}`} onClick={() => handleTableClick(table)}>
                        <div className="staff-table-label">{table.label}</div>
                        <div className={`staff-table-status ${table.status || 'available'}`}>
                          {table.status === 'available' ? 'FREE' : table.status === 'occupied' ? 'BUSY' : (table.status || 'FREE').toUpperCase()}
                        </div>
                        {table.customerName && <div className="staff-table-customer">{table.customerName}</div>}
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {customerModal && (
          <div className="modal-backdrop" onClick={() => setCustomerModal(null)}>
            <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '360px' }}>
              <div className="modal-header">
                <h3 className="modal-title">NEW ORDER — {customerModal.label}</h3>
                <button className="btn btn-ghost btn-icon" onClick={() => setCustomerModal(null)}>✕</button>
              </div>
              <div className="modal-body">
                <div className="input-group">
                  <label className="input-label">Customer Name (Optional)</label>
                  <input className="input" placeholder="Enter name..." value={customerName}
                    onChange={e => setCustomerName(e.target.value)} autoFocus
                    onKeyDown={e => { if (e.key === 'Enter') handleStartOrder(); }} />
                </div>
              </div>
              <div className="modal-footer">
                <button className="btn btn-secondary" onClick={() => setCustomerModal(null)}>Cancel</button>
                <button className="btn btn-success btn-lg" onClick={handleStartOrder} disabled={busy}>
                  {busy ? 'STARTING...' : 'START ORDER'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }



  return (
    <div className="staff-mobile">
      <div className="staff-order-header">
        <button className="staff-back-btn" onClick={handleBack}>
          <ArrowLeft size={18} />
        </button>
        <div className="staff-order-table-info">
          <div className="staff-order-table-name">{selectedTable?.label || 'Table'}</div>
          {selectedTable?.customerName && <div className="staff-order-customer">{selectedTable.customerName}</div>}
        </div>
        <button className="staff-kot-btn" onClick={handlePrintSplitKOT} disabled={safeItems.length === 0}>
          <Printer size={14} /> KOT
        </button>
        <button className="staff-bill-btn" onClick={() => setBillModal(true)} disabled={safeItems.length === 0}>
          <Receipt size={14} /> BILL
        </button>
      </div>

      {safeItems.length > 0 && (
        <>
        <div className="staff-order-items">
          <div className="staff-order-items-header">
            <span>ORDER ({safeItems.length})</span>
            <span className="staff-order-total">{config.currency}{subtotal}</span>
          </div>
          <div className="staff-order-items-list">
            {depts.map(dept => {
               const deptCatIds = categories.filter(c => c.type === dept.id).map(c => c.id);
               const deptOrderItems = safeItems.filter(i => deptCatIds.includes(i.categoryId));
               if (deptOrderItems.length === 0) return null;
               return (
                 <div key={dept.id}>
                   <div className="staff-order-section-label"><Package size={12} /> {dept.name.toUpperCase()} ({deptOrderItems.length})</div>
                   {deptOrderItems.map(item => <OrderItemRow key={item.id} item={item} config={config} busy={busy}
                     onQty={handleQtyChange} onRemove={handleRemoveItem} onNote={(it) => { setNoteModal(it); setNoteText(it.note || ''); }} />)}
                 </div>
               );
            })}
          </div>
        </div>
        <div style={{ padding: '0 12px 12px 12px' }}>
            <button className="btn btn-ghost" style={{ color: 'var(--brand-danger)', width: '100%', fontSize: '12px' }} onClick={handleCancelOrder} disabled={busy}>
              CANCEL ORDER
            </button>
        </div>
        </>
      )}

      <div className="staff-menu-search">
        <Search size={16} />
        <input type="text" placeholder="Search items..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
        {searchQuery && <button className="staff-search-clear" onClick={() => setSearchQuery('')}><X size={14} /></button>}
      </div>

      <div className="staff-menu-toggle" style={{ overflowX: 'auto', flexWrap: 'nowrap' }}>
        {depts.map(dept => (
          <button key={dept.id} className={`staff-toggle-btn ${activeDeptId === dept.id ? 'active' : ''}`}
            onClick={() => { setActiveDeptId(dept.id); setActiveCategory('all'); }}>
            {dept.name.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="staff-category-scroll">
        <button className={`staff-cat-tab ${activeCategory === 'all' ? 'active' : ''}`}
          onClick={() => setActiveCategory('all')}>ALL</button>
        {deptCategories.map(cat => (
          <button key={cat.id} className={`staff-cat-tab ${activeCategory === cat.id ? 'active' : ''}`}
            onClick={() => setActiveCategory(cat.id)}>{cat.icon} {cat.name}</button>
        ))}
      </div>

      <div className="staff-menu-grid">
        {filteredItems.map(item => {
          const isOOS = false; // Bypass OOS completely so items can be selected unconditionally
          return (
            <div
              key={item.id}
              className={`staff-menu-card ${isOOS ? 'oos' : ''}`}
              onClick={() => !isOOS && handleAddItem(item)}
              style={busy && !isOOS ? { opacity: 0.6, pointerEvents: 'none' } : undefined}
            >
              <div className="staff-menu-card-name">{item.name}</div>
              <div className="staff-menu-card-bottom">
                <span className="staff-menu-card-price">{config.currency}{item.price}</span>
              </div>
              {isOOS && <div className="staff-oos-badge">OUT</div>}
            </div>
          );
        })}
        {filteredItems.length === 0 && <div className="staff-empty">No items found</div>}
      </div>

      {noteModal && (
        <div className="modal-backdrop" onClick={() => setNoteModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '360px' }}>
            <div className="modal-header">
              <h3 className="modal-title">NOTE — {noteModal.name}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setNoteModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <textarea className="input" placeholder="e.g., No ice, extra lime..." value={noteText}
                onChange={e => setNoteText(e.target.value)} rows={2} autoFocus />
              <div style={{ display: 'flex', gap: '4px', marginTop: '8px', flexWrap: 'wrap' }}>
                {['No ice', 'Extra lime', 'On the rocks', 'Neat', 'With soda', 'Spicy', 'Less salt'].map(q => (
                  <button key={q} className="btn btn-sm btn-secondary" onClick={() => setNoteText(prev => prev ? `${prev}, ${q}` : q)}>{q}</button>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setNoteModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleAddNote} disabled={busy}>Save</button>
            </div>
          </div>
        </div>
      )}

      {billModal && (
        <div className="modal-backdrop" onClick={() => setBillModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '380px' }}>
            <div className="modal-header">
              <h3 className="modal-title">BILL — {selectedTable?.label || 'Table'}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setBillModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div style={{ marginBottom: '12px', maxHeight: '200px', overflow: 'auto', background: 'var(--bg-tertiary)', borderRadius: 'var(--radius-md)', padding: '8px' }}>
                {safeItems.map(item => (
                  <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '2px 0', fontSize: '11px' }}>
                    <span>{item.name} ×{item.quantity}</span>
                    <span style={{ fontFamily: 'var(--font-mono)', fontWeight: 600 }}>{config.currency}{(item.price || 0) * (item.quantity || 0)}</span>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: '11px', fontWeight: 700, fontFamily: 'var(--font-mono)', marginBottom: '8px' }}>PAYMENT</div>
              <div className="payment-modes" style={{ marginBottom: '12px' }}>
                {[{ mode: 'Cash', icon: Banknote }, { mode: 'Card', icon: CreditCard }, { mode: 'UPI', icon: Smartphone }].map(p => (
                  <button key={p.mode} className={`payment-mode-btn ${paymentMode === p.mode ? 'active' : ''}`}
                    onClick={() => setPaymentMode(p.mode)}><p.icon size={18} /><span>{p.mode}</span></button>
                ))}
              </div>
              <div className="input-group">
                <label className="input-label">Discount (%)</label>
                <input type="number" className="input" value={discount}
                  onChange={e => setDiscount(Math.max(0, Math.min(100, Number(e.target.value) || 0)))} min="0" max="100" />
              </div>
              <div style={{ borderTop: '2px solid var(--border-color)', paddingTop: '8px', marginTop: '8px' }}>
                <div className="order-summary-row"><span>Subtotal</span><span>{config.currency}{subtotal}</span></div>
